  "analysis": "The single tesseract call from Python works fine and returns output successfully. The issue with the parallel script was likely that too many tesseract processes overwhelmed the system, causing timeouts. We need a more controlled parallel approach with fewer workers (e.g., 2) and longer timeouts, or process frames in small sequential batches. Given that single OCR takes about 0.8s, even sequential processing of 190 frames should take about 150 seconds. Let me try a sequential approach with progress tracking, or use 2 workers with 30s timeout.",
  "plan": "Rewrite the OCR script to use 2 workers with 30-second timeout, and also print error details for failures. This should be fast enough while avoiding overwhelming the system.",
  "commands": [
    {
      "keystrokes": "cat > /app/ocr_parallel.py << 'PYEOF'
#!/usr/bin/env python3
import subprocess
import os
import concurrent.futures

FRAMES_DIR = '/app/frames1'

def ocr_frame(fname):
    fpath = os.path.join(FRAMES_DIR, fname)
    txtpath = fpath + '.txt'
    try:
        result = subprocess.run(['tesseract', fpath, 'stdout'],
                              capture_output=True, text=True, timeout=30)
        with open(txtpath, 'w') as f:
            f.write(result.stdout)
        return fname, True, ''
    except subprocess.TimeoutExpired:
        return fname, False, 'TIMEOUT'
    except Exception as e:
        return fname, False, str(e)

frames = sorted([f for f in os.listdir(FRAMES_DIR) if f.endswith('.png')])
# Remove already processed files
frames = [f for f in frames if not os.path.exists(os.path.join(FRAMES_DIR, f + '.txt'))]
print(f"Processing {len(frames)} frames...", flush=True)

with concurrent.futures.ThreadPoolExecutor(max_workers=2) as executor:
    futures = {executor.submit(ocr_frame, f): f for f in frames}
    done = 0
    ok = 0
    for future in concurrent.futures.as_completed(futures):
        fname, success, err = future.result()
        done += 1
        if success:
            ok += 1
        else:
            print(f"FAIL {fname}: {err}", flush=True)
        if done % 20 == 0 or done == len(frames):
            print(f"{done}/{len(frames)} done, {ok} ok", flush=True)

print(f"Complete: {ok}/{len(frames)} succeeded")
PYEOF
